@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]

@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_628d5741e671484d8650ca5a334ea320.Data

@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users and their roles.</p>

@if (userList is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in userList)
            {
                <tr>
                    <td>@user.FullName</td>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(ApplicationUser User, IList<string> Roles)>? userList;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userList = [];
        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userList.Add((user, roles));
        }
    }
}

